Вычислитель
Это последний этап, на котором мы обходим AST узел за узлом и выполняем то, что там записано: создаём переменные, функции, поддерживаем окружения (области видимости) и делаем многое другое.
func Eval(node ast.Node, env *Environment) Value {
	switch node := node.(type) {
	case *ast.Program:
 return evalProgram(node, env)
	case *ast.VarStatement:
 return evalVarStatement(node, env)
	case *ast.ReturnStatement:
 return evalReturnStatement(node, env)
	case *ast.ExpressionStatement:
 return Eval(node.Expression, env)
	case *ast.BlockStatement:
 return evalBlockStatement(node, env)
	case *ast.IfStatement:
 return evalIfStatement(node, env)
	case *ast.WhileStatement:
 return evalWhileStatement(node, env)
	case *ast.NumberLiteral:
 return node.Value
	case *ast.StringLiteral:
 return node.Value
	case *ast.BooleanLiteral:
 return node.Value
	case *ast.Identifier:
 return evalIdentifier(node, env)
	case *ast.PrefixExpression:
 return evalPrefixExpression(node, env)
	case *ast.InfixExpression:
 return evalInfixExpression(node, env)
	case *ast.AssignExpression:
 return evalAssignExpression(node, env)
	case *ast.FunctionLiteral:
 return &Function{
 Parameters: node.Parameters,
 Body: node.Body,
 Env: env,
 }
	case *ast.CallExpression:
 return evalCallExpression(node, env)
	case *ast.ObjectLiteral:
 return evalObjectLiteral(node, env)
	case *ast.PropertyAccess:
 return evalPropertyAccess(node, env)
	}

	return nil
}
Что именно происходит в рамках каждой операции вычисления, зависит от типа обрабатываемого узла. Например,
evalVarStatement
просто сохраняет значение в окружении
Env.set(node.Name, node.Value)
. Если узел представляет функцию, то движок создаёт новое окружение (область видимости функции), а затем выполняет тело функции в этом контексте.
func evalVarStatement(node *ast.VarStatement, env *Environment) Value {
 var val Value = nil

 if node.Value != nil {
 val = Eval(node.Value, env)
 }

 env.Set(node.Name, val)
 return val
}
Как видите, в некоторых случаях мы вызываем
Eval
рекурсивно. Дело в том, что
node.Value
не всегда является простым значением, оно может быть и другим выражением. Рассмотрим, например,
var x = 5 + 2
. Здесь
Value
— это
InfixExpression
. При повторном вызове Eval делегирует выполнение к evalInfixExpression, которая обрабатывает узел, а затем соответствующим образом вычисляет выражение.
Реализация встроенных функций
К настоящему моменту, вероятно, общая структура работы уже понятна: читаем код символ за символом, токенизируем его, строим абстрактное синтаксическое дерево, а затем выполняем. Вероятно, вы уже заметили, что мы используем функцию
print,
а не
console.log
— причём, намеренно. Далее рассмотрим, как она реализована и расширим наш интерпретатор, добавив в него
fetch, JSON
и встроенные функции массивов.
При парсинге выражения вызова обнаруживается, что оно может приводить к 4 разным случаям:
Вызов встроенной функции, напр.
print, fetch
Вызов встроенной функции через доступ к свойству, напр.
JSON
.parse
Определяемый пользователем вызов функции, напр.
sum, add
Ошибка, недопустимый вызов функции
func evalCallExpression(node *ast.CallExpression, env *Environment) Value {
	// Проверяем наличие встроенных функций
	if ident, ok := node.Function.(*ast.Identifier); ok {
 if builtin, ok := builtins.Get(ident.Name); ok {
 args := []interface{}{}
 for _, arg := range node.Arguments {
 args = append(args, Eval(arg, env))
 }
 return builtin.Fn(args...)
 }
	}

	function := Eval(node.Function, env)

	// Проверяем, происходит ли обращение к встроенной функции через доступ к свойству (напр., JSON.stringify)
	if builtin, ok := function.(*builtins.Builtin); ok {
 args := []interface{}{}
 for _, arg := range node.Arguments {
 args = append(args, Eval(arg, env))
 }
 return builtin.Fn(args...)
	}

	// ...

	return result
}
Под
evaluator/builtins
у нас есть пакет, в котором определяются такие функции как
print , fetch , JSON
.* , встроенные функции для работы с массивами и главный файл пакета:
type Builtin struct {
	Name string
	Fn func(args ...interface{}) interface{}
}

var builtins = map[string]*Builtin{
	"print": {Name: print.Print.Name, Fn: print.Print.Fn},
	"fetch": {Name: fetch.Fetch.Name, Fn: fetch.Fetch.Fn},
}

var jsonNamespace = make(map[string]*Builtin)

func init() {
	for key, builtin := range json.JSON {
 jsonNamespace[key] = &Builtin{Name: builtin.Name, Fn: builtin.Fn}
	}
}

func Get(name string) (*Builtin, bool) {
	builtin, ok := builtins[name]
	return builtin, ok
}

func GetJSON() map[string]*Builtin {
	return jsonNamespace
}
Как только интерпретатор видит выражение, соответствующее вызову функции, он пытается найти идентификатор встроенной функции. Если такой идентификатор существует, то он выполняет (осень простую) встроенную функцию, написанную на Go.
var Print = &Builtin{
	Name: "print",
	Fn: func(args ...interface{}) interface{} {
 for i, arg := range args {
 if i > 0 {
 fmt.Print(" ")
 }
 fmt.Print(internal.ToString(arg))
 }
 fmt.Println()
 return nil
	},
}
